import{_ as a}from"./chunks/Dashboard_ComputerMaintenance_Dark.DR4f9QTw.js";import{_ as r}from"./chunks/Wizard_EmojiIcons_Dark.D5AWBPVC.js";import{_ as i}from"./chunks/Dashboard_ScriptCards_Dark.C3p9XNNL.js";import{_ as o,o as t,c as s,ae as l}from"./chunks/framework.CM88uqJ3.js";const n="/PoshUI/assets/Wizard_Dark_1.CNwnFFVx.png",h="/PoshUI/assets/Workflow.DoTqFQh3.png",I=JSON.parse('{"title":"About","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),m={name:"index.md"};function d(c,e,p,u,f,g){return t(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><p>Build beautiful PowerShell wizards, dashboards, and workflows—the PowerShell way.</p><p><img src="'+a+'" alt="PoshUI Dashboard"></p><p>PoshUI enables IT professionals to create professional Windows 11-style interfaces using familiar PowerShell cmdlets—<strong>no WPF, XAML, or C# knowledge required</strong>.</p><h2 id="three-independent-modules" tabindex="-1">Three Independent Modules <a class="header-anchor" href="#three-independent-modules" aria-label="Permalink to &quot;Three Independent Modules&quot;">​</a></h2><p>PoshUI consists of three independent modules that can be used separately:</p><h3 id="poshui-wizard" tabindex="-1">PoshUI.Wizard <a class="header-anchor" href="#poshui-wizard" aria-label="Permalink to &quot;PoshUI.Wizard&quot;">​</a></h3><p>Create step-by-step guided interfaces for configuration, deployment, and setup workflows. Perfect for server provisioning, VM creation, and application deployment.</p><p><img src="'+n+'" alt="Wizard Dark Theme"></p><p>Full-color PNG emoji icons on every UI element <em>(v1.3.0)</em>:</p><p><img src="'+r+'" alt="Wizard with Emoji Icons"></p><ul><li><a href="./wizards/steps.html">Step-by-Step Navigation</a></li><li><a href="./controls/about.html">12+ Built-in Controls</a></li><li><a href="./wizards/execution.html">Live Execution Console</a></li><li><a href="./wizards/branding.html">Branding &amp; Customization</a></li><li><a href="./controls/dynamic-controls.html">Dynamic Data Sources</a></li><li><a href="./platform/validation.html">Input Validation &amp; Error Handling</a></li><li><a href="./configuration/icons.html">PNG Icon Support</a> <em>(v1.3.0)</em></li><li><a href="./platform/custom-themes.html">Dual-Mode Custom Themes</a> <em>(v1.3.0)</em></li></ul><h3 id="poshui-dashboard" tabindex="-1">PoshUI.Dashboard <a class="header-anchor" href="#poshui-dashboard" aria-label="Permalink to &quot;PoshUI.Dashboard&quot;">​</a></h3><p>Build card-based monitoring interfaces with metrics, charts, and interactive tools. Perfect for system monitoring, KPI displays, IT operations centers, and sharing tools with your team.</p><p><img src="'+a+'" alt="Dashboard with PNG Icons"></p><ul><li><a href="./visualization/metric-cards.html">MetricCards</a> - Display KPIs and system metrics</li><li><a href="./visualization/graph-cards.html">GraphCards (Bar, Line, Area, Pie)</a> - Visualize trends and data</li><li><a href="./visualization/datagrid-cards.html">DataGridCards</a> - Show tabular data</li><li><a href="./visualization/script-cards.html">ScriptCards</a> - Turn scripts into clickable tools for end users</li><li><a href="./carousel-clickable-links.html">Carousel Banners with PNG Icons</a> - Clickable carousel slides with per-slide PNG icons <em>(v1.3.0)</em></li><li><a href="./dashboards/categories.html">Category Filtering</a> - Organize cards into filterable groups</li><li><a href="./dashboards/refresh.html">Real-time Data Updates</a> - Auto-refresh cards with live PowerShell execution</li><li><a href="./configuration/icons.html">PNG Icon Support</a> - Full-color icons on steps, cards, and banners <em>(v1.3.0)</em></li><li><a href="./platform/custom-themes.html">Dual-Mode Custom Themes</a> <em>(v1.3.0)</em></li></ul><p><strong>ScriptCards</strong> with PNG icons empower end users to run PowerShell scripts with a single click:</p><p><img src="'+i+'" alt="ScriptCard with PNG Icons"></p><h3 id="poshui-workflow" tabindex="-1">PoshUI.Workflow <a class="header-anchor" href="#poshui-workflow" aria-label="Permalink to &quot;PoshUI.Workflow&quot;">​</a></h3><p>Orchestrate multi-step automated processes with progress tracking, approval gates, and reboot/resume capabilities. Perfect for server deployments, software installations, and maintenance tasks.</p><p><img src="'+h+'" alt="Workflow Execution"></p><ul><li><a href="./workflows/tasks.html">Task-Based Execution</a></li><li><a href="./workflows/progress-reporting.html">Progress Tracking</a></li><li><a href="./workflows/about.html">Approval Gates</a></li><li><a href="./workflows/reboot-resume.html">Reboot &amp; Resume</a></li><li><a href="./workflows/data-passing.html">Data Passing Between Tasks</a></li><li><a href="./workflows/logging.html">Workflow Logging</a></li></ul><h2 id="platform" tabindex="-1">Platform <a class="header-anchor" href="#platform" aria-label="Permalink to &quot;Platform&quot;">​</a></h2><p>Built on .NET Framework 4.8 with a hybrid architecture combining PowerShell flexibility with WPF rendering power.</p><ul><li><a href="./system-requirements.html">Windows PowerShell 5.1 Support</a></li><li><a href="./system-requirements.html">Windows 10/11 &amp; Server 2016+</a></li><li><a href="./platform/theming.html">Light/Dark Theme Support</a> with runtime toggle <em>(v1.3.0)</em></li><li><a href="./platform/custom-themes.html">Dual-Mode Custom Themes</a> <em>(v1.3.0)</em></li><li><a href="./configuration/icons.html">PNG Icon Support</a> across all modules <em>(v1.3.0)</em></li><li><a href="./platform/logging.html">CMTrace-Compatible Logging</a></li><li><a href="./installation.html">No External Dependencies</a></li></ul><h2 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h2><p>Join the PoshUI community and contribute to the project.</p><ul><li><a href="https://github.com/Kanders-II/PoshUI" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://github.com/Kanders-II/PoshUI/issues" target="_blank" rel="noreferrer">Issue Tracker</a></li><li><a href="https://github.com/Kanders-II/PoshUI/discussions" target="_blank" rel="noreferrer">Discussions</a></li></ul><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><p>PoshUI is open source under the MIT License.</p><p><a href="./licensing.html">View License</a></p>',31)])])}const _=o(m,[["render",d]]);export{I as __pageData,_ as default};
